"use client";
import { useState } from "react";
import { useRouter } from "next/navigation";

interface SearchBarProps {
    size?: "lg" | "sm";
}

export default function SearchBar({ size = "lg" }: SearchBarProps) {
    const [keyword, setKeyword] = useState("");
    const [location, setLocation] = useState("");
    const router = useRouter();

    const handleSearch = (e: React.FormEvent) => {
        e.preventDefault();
        const params = new URLSearchParams();
        if (keyword) params.set("q", keyword);
        if (location) params.set("loc", location);
        router.push(`/jobs?${params.toString()}`);
    };

    const isLg = size === "lg";

    return (
        <form
            onSubmit={handleSearch}
            style={{
                display: "flex",
                gap: isLg ? "0" : "0.5rem",
                background: "var(--bg-card)",
                borderRadius: isLg ? "12px" : "8px",
                border: "2px solid var(--border)",
                boxShadow: "var(--shadow-md)",
                overflow: isLg ? "hidden" : "visible",
                flexWrap: isLg ? undefined : "wrap",
                transition: "border-color 200ms",
            }}
            onFocus={(e) => ((e.currentTarget as HTMLFormElement).style.borderColor = "var(--primary)")}
            onBlur={(e) => ((e.currentTarget as HTMLFormElement).style.borderColor = "var(--border)")}
        >
            {/* Keyword input */}
            <div style={{ display: "flex", alignItems: "center", flex: 2, padding: isLg ? "0 1.25rem" : "0", minWidth: 0 }}>
                <svg
                    width="18"
                    height="18"
                    fill="none"
                    stroke="var(--primary)"
                    strokeWidth="2"
                    viewBox="0 0 24 24"
                    style={{ flexShrink: 0, marginRight: "0.5rem" }}
                >
                    <circle cx="11" cy="11" r="8" />
                    <path strokeLinecap="round" d="M21 21l-4.35-4.35" />
                </svg>
                <input
                    type="text"
                    placeholder="Tên công việc, kỹ năng, công ty..."
                    value={keyword}
                    onChange={(e) => setKeyword(e.target.value)}
                    style={{
                        border: "none",
                        outline: "none",
                        background: "transparent",
                        fontFamily: "inherit",
                        fontSize: isLg ? "0.9375rem" : "0.875rem",
                        color: "var(--text)",
                        width: "100%",
                        padding: isLg ? "1rem 0" : "0.75rem 1rem",
                    }}
                />
            </div>

            {/* Divider */}
            {isLg && (
                <div style={{ width: "1.5px", background: "var(--border)", margin: "0.75rem 0" }} />
            )}

            {/* Location input */}
            <div style={{ display: "flex", alignItems: "center", flex: 1, padding: isLg ? "0 1.25rem" : "0", minWidth: 0 }}>
                <svg
                    width="18"
                    height="18"
                    fill="none"
                    stroke="var(--primary)"
                    strokeWidth="2"
                    viewBox="0 0 24 24"
                    style={{ flexShrink: 0, marginRight: "0.5rem" }}
                >
                    <path
                        strokeLinecap="round"
                        strokeLinejoin="round"
                        d="M17.657 16.657L13.414 20.9a1.998 1.998 0 0 1-2.827 0l-4.244-4.243a8 8 0 1 1 11.314 0z"
                    />
                    <path strokeLinecap="round" strokeLinejoin="round" d="M15 11a3 3 0 1 1-6 0 3 3 0 0 1 6 0z" />
                </svg>
                <input
                    type="text"
                    placeholder="Địa điểm: Hà Nội, TP.HCM..."
                    value={location}
                    onChange={(e) => setLocation(e.target.value)}
                    style={{
                        border: "none",
                        outline: "none",
                        background: "transparent",
                        fontFamily: "inherit",
                        fontSize: isLg ? "0.9375rem" : "0.875rem",
                        color: "var(--text)",
                        width: "100%",
                        padding: isLg ? "1rem 0" : "0.75rem 1rem",
                    }}
                />
            </div>

            {/* Submit */}
            <button
                type="submit"
                className="btn-primary"
                style={{
                    borderRadius: isLg ? "0 10px 10px 0" : "8px",
                    padding: isLg ? "1rem 2rem" : "0.75rem 1.25rem",
                    fontSize: "0.9375rem",
                    margin: isLg ? "0" : "0.5rem 0 0.5rem 0.5rem",
                }}
            >
                <svg width="18" height="18" fill="none" stroke="currentColor" strokeWidth="2" viewBox="0 0 24 24">
                    <circle cx="11" cy="11" r="8" />
                    <path strokeLinecap="round" d="M21 21l-4.35-4.35" />
                </svg>
                Tìm kiếm
            </button>
        </form>
    );
}
